const resolveImg = (item) => {
  if (item?.primary_image_url) return item.primary_image_url;
  if (Array.isArray(item?.images) && item.images.length) {
    const p = item.images.find((i) => i.is_primary);
    return (p || item.images[0]).image_url || "";
  }
  return item?.image_url || item?.image || item?.thumbnail_url || "";
};
const resolveTags = (item) => {
  if (Array.isArray(item?.style_tags)) return item.style_tags;
  if (item?.style_tags?.tags) return item.style_tags.tags;
  if (Array.isArray(item?.tags)) return item.tags;
  return [];
};
const resolvePrice = (item) =>
  Math.round((item?.sale_price || item?.base_price || item?.price || 0) / 10);
const resolveScore = (item) =>
  Math.round((item?.match_score || item?.score || 0.85) * 100);
const cleanName = (item) => {
  return item?.name || item?.title || "Fashion Item";
};
const hashInt = (s) => {
  let h = 0;
  for (let i = 0; i < (s||"").length; i++) h = ((h << 5) - h + (s||"").charCodeAt(i)) | 0;
  return Math.abs(h);
};
const mockRating = (item) => {
  const h = hashInt(String(item?.catalog_item_id || item?.id || "x"));
  return { stars: (3.8 + (h % 11) / 10).toFixed(1), reviews: 100 + (h % 4901) };
};

