function highlightMatch(text, query) {
  if (!query) return text;
  const idx = text.toLowerCase().indexOf(query.toLowerCase());
  if (idx === -1) return text;
  return (
    <>
      {text.slice(0, idx)}
      <strong style={{ color: "#d4a8ff", fontWeight: 600 }}>{text.slice(idx, idx + query.length)}</strong>
      {text.slice(idx + query.length)}
    </>
  );
}

function CityAutocomplete({ value, onChange }) {
  const [query, setQuery] = useState(value || "");
  const [open, setOpen]   = useState(false);
  const [active, setActive] = useState(-1);
  const [focused, setFocused] = useState(false);
  const [detecting, setDetecting] = useState(false);
  const wrapRef  = useRef(null);
  const inputRef = useRef(null);
  const listRef  = useRef(null);

  // Substring search — starts-with ranked first
  const filtered = useMemo(() => {
    if (!query.trim()) return [];
    const q = query.toLowerCase();
    const starts = ALL_CITIES.filter((c) => c.name.toLowerCase().startsWith(q));
    const contains = ALL_CITIES.filter(
      (c) => !c.name.toLowerCase().startsWith(q) && c.name.toLowerCase().includes(q)
    );
    return [...starts, ...contains].slice(0, 10);
  }, [query]);

  useEffect(() => {
    function handleClick(e) {
      if (wrapRef.current && !wrapRef.current.contains(e.target)) setOpen(false);
    }
    document.addEventListener("mousedown", handleClick);
    return () => document.removeEventListener("mousedown", handleClick);
  }, []);

  // Scroll active item into view
  useEffect(() => {
    if (active >= 0 && listRef.current) {
      const el = listRef.current.children[active];
      el?.scrollIntoView({ block: "nearest" });
    }
  }, [active]);

  function handleKeyDown(e) {
    if (!open || filtered.length === 0) return;
    if (e.key === "ArrowDown") { e.preventDefault(); setActive((a) => Math.min(a + 1, filtered.length - 1)); }
    if (e.key === "ArrowUp")   { e.preventDefault(); setActive((a) => Math.max(a - 1, 0)); }
    if (e.key === "Enter" && active >= 0) { e.preventDefault(); select(filtered[active]); }
    if (e.key === "Escape") setOpen(false);
  }

  function select(city) {
    setQuery(city.name);
    onChange(city.name);
    setOpen(false);
    setActive(-1);
  }

  function detectLocation() {
    if (!navigator.geolocation) return;
    setDetecting(true);
    navigator.geolocation.getCurrentPosition(
      async (pos) => {
        try {
          const { latitude: lat, longitude: lon } = pos.coords;
          const res = await fetch(
            `https://nominatim.openstreetmap.org/reverse?lat=${lat}&lon=${lon}&format=json`
          );
          const data = await res.json();
          const city =
            data.address?.city ||
            data.address?.town ||
            data.address?.village ||
            data.address?.county ||
            "";
          if (city) { setQuery(city); onChange(city); }
        } catch (_) {}
        setDetecting(false);
      },
      () => setDetecting(false),
      { timeout: 6000 }
    );
  }

  const floatUp = focused || query.length > 0;

  return (
    <div ref={wrapRef} style={{ position: "relative", width: "100%" }}>
      {/* gradient border wrapper */}
      <div style={{
        padding: 2,
        borderRadius: 22,
        background: focused
          ? "linear-gradient(135deg,#fab7fb,#a855f7,#3b82f6,#fab7fb)"
          : "rgba(255,255,255,0.14)",
        backgroundSize: "200% 200%",
        animation: focused ? "gradientShift 3s ease infinite" : "none",
        boxShadow: focused ? "0 0 22px rgba(168,85,247,0.2)" : "none",
        transition: "box-shadow 0.3s",
      }}>
        <div style={{
          position: "relative",
          background: "rgba(12,4,36,0.82)",
          backdropFilter: "blur(40px)",
          WebkitBackdropFilter: "blur(40px)",
          borderRadius: 20,
          padding: "26px 52px 12px 20px",
          cursor: "text",
        }} onClick={() => inputRef.current?.focus()}>

          {/* floating label */}
          <label style={{
            position: "absolute",
            left: 20,
            top: floatUp ? 8 : "50%",
            transform: floatUp ? "translateY(0) scale(0.76)" : "translateY(-50%)",
            transformOrigin: "left center",
            color: focused ? "#d4a8ff" : "rgba(255,255,255,0.4)",
            fontSize: 19,
            fontFamily: "'League Spartan',sans-serif",
            fontWeight: 400,
            letterSpacing: 0.3,
            transition: "all 0.22s cubic-bezier(0.4,0,0.2,1)",
            pointerEvents: "none",
            zIndex: 5,
            whiteSpace: "nowrap",
          }}>
            City / Location
          </label>

          <div style={{ display: "flex", alignItems: "center", gap: 8 }}>
            <input
              ref={inputRef}
              type="text"
              value={query}
              onChange={(e) => {
                setQuery(e.target.value);
                onChange(e.target.value);
                setOpen(true);
                setActive(-1);
              }}
              onFocus={() => { setFocused(true); setOpen(true); }}
              onBlur={() => setFocused(false)}
              onKeyDown={handleKeyDown}
              autoComplete="off"
              style={{
                background: "transparent",
                border: "none",
                outline: "none",
                color: "#fff",
                fontSize: 21,
                fontFamily: "'League Spartan',sans-serif",
                fontWeight: 300,
                width: "100%",
                position: "relative",
                zIndex: 3,
                lineHeight: 1,
              }}
            />
          </div>
        </div>

        {/* detect location button — right side */}
        <button
          type="button"
          onClick={detectLocation}
          title="Detect my location"
          style={{
            position: "absolute",
            right: 10, top: "50%",
            transform: "translateY(-50%)",
            width: 36, height: 36,
            borderRadius: "50%",
            background: detecting ? "rgba(168,85,247,0.3)" : "rgba(255,255,255,0.08)",
            border: "1px solid rgba(255,255,255,0.15)",
            cursor: detecting ? "default" : "pointer",
            display: "flex", alignItems: "center", justifyContent: "center",
            transition: "background 0.2s",
            zIndex: 10,
          }}
          onMouseEnter={e => !detecting && (e.currentTarget.style.background = "rgba(168,85,247,0.25)")}
          onMouseLeave={e => !detecting && (e.currentTarget.style.background = "rgba(255,255,255,0.08)")}
        >
          {detecting ? (
            <div style={{
              width: 16, height: 16,
              border: "2px solid rgba(255,255,255,0.3)",
              borderTopColor: "#d4a8ff",
              borderRadius: "50%",
              animation: "spin 0.7s linear infinite",
            }}/>
          ) : (
            <svg width="17" height="17" viewBox="0 0 24 24" fill="none" stroke="rgba(255,255,255,0.7)" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round">
              <circle cx="12" cy="12" r="3"/>
              <path d="M12 2v3M12 19v3M2 12h3M19 12h3"/>
              <circle cx="12" cy="12" r="9" strokeOpacity="0.3"/>
            </svg>
          )}
        </button>
      </div>

      {/* dropdown */}
      {open && filtered.length > 0 && (
        <div style={{
          position: "absolute",
          top: "calc(100% + 8px)",
          left: 0, right: 0,
          background: "rgba(14,6,42,0.97)",
          backdropFilter: "blur(30px)",
          WebkitBackdropFilter: "blur(30px)",
          borderRadius: 18,
          overflow: "hidden",
          zIndex: 999,
          boxShadow: "0 12px 40px rgba(0,0,0,0.5), 0 0 0 1px rgba(168,85,247,0.2)",
          animation: "fadeUp 0.15s ease both",
          maxHeight: 340,
          overflowY: "auto",
        }} ref={listRef}>
          {filtered.map((city, i) => (
            <div
              key={`${city.name}-${i}`}
              onMouseDown={() => select(city)}
              onMouseEnter={() => setActive(i)}
              style={{
                padding: "13px 20px",
                cursor: "pointer",
                background: active === i ? "rgba(168,85,247,0.18)" : "transparent",
                borderBottom: "1px solid rgba(255,255,255,0.05)",
                display: "flex",
                alignItems: "center",
                gap: 12,
                transition: "background 0.1s",
              }}
            >
              {/* pin icon */}
              <svg width="15" height="15" viewBox="0 0 24 24" fill="none"
                stroke={active === i ? "#d4a8ff" : "rgba(255,255,255,0.35)"}
                strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"
                style={{ flexShrink: 0, transition: "stroke 0.15s" }}>
                <path d="M21 10c0 7-9 13-9 13S3 17 3 10a9 9 0 0118 0z"/>
                <circle cx="12" cy="10" r="3"/>
              </svg>
              <div>
                <div style={{
                  color: "#fff",
                  fontFamily: "'League Spartan',sans-serif",
                  fontSize: 18,
                  fontWeight: 400,
                  lineHeight: 1.2,
                }}>
                  {highlightMatch(city.name, query)}
                </div>
                <div style={{
                  color: "rgba(255,255,255,0.38)",
                  fontFamily: "'League Spartan',sans-serif",
                  fontSize: 12,
                  fontWeight: 300,
                  marginTop: 1,
                }}>
                  {city.region}
                </div>
              </div>
            </div>
          ))}
        </div>
      )}
    </div>
  );
}

