function AgeInput({ value, onChange }) {
  const num = Number(value) || 0;
  const MIN = 13, MAX = 95;
  const hasVal = num >= MIN;

  function step(delta) {
    const next = Math.min(MAX, Math.max(MIN, (num || MIN) + delta));
    onChange(String(next));
  }

  return (
    <div style={{
      padding: 2,
      borderRadius: 22,
      background: hasVal
        ? "linear-gradient(135deg,#fab7fb,#a855f7,#3b82f6)"
        : "rgba(255,255,255,0.14)",
      boxShadow: hasVal ? "0 0 22px rgba(168,85,247,0.2)" : "none",
      transition: "all 0.3s",
    }}>
      <div style={{
        borderRadius: 20,
        background: "rgba(12,4,36,0.82)",
        backdropFilter: "blur(40px)",
        WebkitBackdropFilter: "blur(40px)",
        padding: "12px 14px",
        display: "flex",
        alignItems: "center",
        justifyContent: "space-between",
        gap: 8,
      }}>
        {/* label */}
        <span style={{
          fontFamily: "'League Spartan',sans-serif",
          fontSize: 12,
          fontWeight: 400,
          letterSpacing: 0.8,
          color: "rgba(255,255,255,0.35)",
          textTransform: "uppercase",
          whiteSpace: "nowrap",
        }}>Age</span>

        {/* minus */}
        <button type="button" onClick={() => step(-1)} style={{
          width: 32, height: 32, borderRadius: "50%",
          background: "rgba(255,255,255,0.08)",
          border: "1px solid rgba(255,255,255,0.14)",
          color: "rgba(255,255,255,0.7)",
          fontSize: 20, lineHeight: 1,
          cursor: "pointer", display: "flex",
          alignItems: "center", justifyContent: "center",
          flexShrink: 0, fontFamily: "'League Spartan',sans-serif",
          transition: "background 0.15s",
        }}
        onMouseEnter={e => e.currentTarget.style.background = "rgba(168,85,247,0.25)"}
        onMouseLeave={e => e.currentTarget.style.background = "rgba(255,255,255,0.08)"}
        >−</button>

        {/* number display */}
        <div style={{ flex: 1, textAlign: "center" }}>
          {hasVal ? (
            <span style={{
              fontFamily: "'League Spartan',sans-serif",
              fontSize: 32,
              fontWeight: 700,
              color: "#fff",
              letterSpacing: -1,
              animation: "fadeUp 0.15s ease both",
            }}>{num}</span>
          ) : (
            <span style={{
              fontFamily: "'League Spartan',sans-serif",
              fontSize: 15,
              color: "rgba(255,255,255,0.25)",
              fontWeight: 300,
            }}>— yr</span>
          )}
        </div>

        {/* plus */}
        <button type="button" onClick={() => step(1)} style={{
          width: 32, height: 32, borderRadius: "50%",
          background: "rgba(255,255,255,0.08)",
          border: "1px solid rgba(255,255,255,0.14)",
          color: "rgba(255,255,255,0.7)",
          fontSize: 20, lineHeight: 1,
          cursor: "pointer", display: "flex",
          alignItems: "center", justifyContent: "center",
          flexShrink: 0, fontFamily: "'League Spartan',sans-serif",
          transition: "background 0.15s",
        }}
        onMouseEnter={e => e.currentTarget.style.background = "rgba(168,85,247,0.25)"}
        onMouseLeave={e => e.currentTarget.style.background = "rgba(255,255,255,0.08)"}
        >+</button>
      </div>
    </div>
  );
}

