const EMAIL_DOMAINS = ["gmail.com", "yahoo.com", "outlook.com", "hotmail.com", "icloud.com"];
const EMAIL_RE = /^[^\s@]+@[^\s@]+\.[^\s@]{2,}$/;

function EmailInput({ value, onChange }) {
  const [focused, setFocused] = useState(false);
  const inputRef = useRef(null);

  const isValid  = EMAIL_RE.test(value);
  const hasValue = value.length > 0;
  const atIdx    = value.indexOf("@");
  const hasAt    = atIdx !== -1;
  const typedDomain = hasAt ? value.slice(atIdx + 1) : "";

  // clickable chips: domains matching what's after @
  const chips = hasAt
    ? EMAIL_DOMAINS.filter((d) => d.startsWith(typedDomain) && d !== typedDomain)
    : [];

  // ghost tail autocomplete
  const ghostMatch = chips[0] || null;
  const ghostFull  = ghostMatch ? value.slice(0, atIdx + 1) + ghostMatch : "";
  const ghostTail  = ghostFull.startsWith(value) ? ghostFull.slice(value.length) : "";

  function handleKeyDown(e) {
    if ((e.key === "Tab" || e.key === "ArrowRight") && ghostFull) {
      e.preventDefault();
      onChange(ghostFull);
    }
  }

  function acceptDomain(d) {
    const base = hasAt ? value.slice(0, atIdx + 1) : value + "@";
    onChange(base + d);
    inputRef.current?.focus();
  }

  const floatUp = focused || hasValue;

  // gradient border colours
  const gradBorderImage = isValid
    ? "linear-gradient(135deg,#48d296,#00c9a7,#48d296)"
    : focused
    ? "linear-gradient(135deg,#fab7fb,#a855f7,#3b82f6,#fab7fb)"
    : "none";
  const gradBorderColor = (!isValid && !focused) ? "rgba(255,255,255,0.14)" : "transparent";

  const outerShadow = isValid
    ? "0 0 18px rgba(72,210,150,0.25)"
    : focused
    ? "0 0 22px rgba(168,85,247,0.22)"
    : "none";

  return (
    <div style={{ width: "100%" }}>
      {/* animated gradient border wrapper */}
      <div style={{
        padding: 2,
        borderRadius: 22,
        backgroundImage: gradBorderImage,
        backgroundColor: gradBorderColor,
        backgroundSize: "200% 200%",
        animation: focused && !isValid ? "gradientShift 3s ease infinite" : "none",
        boxShadow: outerShadow,
        transition: "box-shadow 0.3s",
      }}>
        <div style={{
          position: "relative",
          background: "rgba(12,4,36,0.82)",
          backdropFilter: "blur(40px)",
          WebkitBackdropFilter: "blur(40px)",
          borderRadius: 20,
          padding: "26px 18px 12px 20px",
          cursor: "text",
        }} onClick={() => inputRef.current?.focus()}>

          {/* floating label */}
          <label style={{
            position: "absolute",
            left: 20,
            top: floatUp ? 8 : "50%",
            transform: floatUp ? "translateY(0) scale(0.76)" : "translateY(-50%)",
            transformOrigin: "left center",
            color: isValid ? "#48d296" : focused ? "#d4a8ff" : "rgba(255,255,255,0.4)",
            fontSize: 19,
            fontFamily: "'League Spartan',sans-serif",
            fontWeight: 400,
            letterSpacing: 0.3,
            transition: "all 0.22s cubic-bezier(0.4,0,0.2,1)",
            pointerEvents: "none",
            zIndex: 5,
            whiteSpace: "nowrap",
          }}>
            Email Address
          </label>

          {/* ghost tail overlay */}
          {ghostTail && (
            <div aria-hidden="true" style={{
              position: "absolute",
              left: 20, right: 50,
              bottom: 12,
              fontSize: 21,
              fontFamily: "'League Spartan',sans-serif",
              fontWeight: 300,
              display: "flex",
              whiteSpace: "pre",
              overflow: "hidden",
              pointerEvents: "none",
              zIndex: 2,
              lineHeight: 1,
              height: 26,
              alignItems: "center",
            }}>
              <span style={{ color: "transparent", whiteSpace: "pre" }}>{value}</span>
              <span style={{ color: "rgba(255,255,255,0.28)" }}>{ghostTail}</span>
            </div>
          )}

          {/* input + right icons row */}
          <div style={{ display: "flex", alignItems: "center", gap: 10 }}>
            <input
              ref={inputRef}
              type="email"
              value={value}
              onChange={(e) => onChange(e.target.value)}
              onKeyDown={handleKeyDown}
              onFocus={() => setFocused(true)}
              onBlur={() => setFocused(false)}
              style={{
                background: "transparent",
                border: "none",
                outline: "none",
                color: "#fff",
                fontSize: 21,
                fontFamily: "'League Spartan',sans-serif",
                fontWeight: 300,
                width: "100%",
                position: "relative",
                zIndex: 3,
                lineHeight: 1,
              }}
            />

            {/* valid checkmark */}
            {isValid && (
              <span style={{
                width: 30, height: 30, borderRadius: "50%",
                background: "linear-gradient(135deg,#48d296,#00c9a7)",
                display: "flex", alignItems: "center", justifyContent: "center",
                flexShrink: 0, animation: "fadeUp 0.18s ease both",
                boxShadow: "0 0 10px rgba(72,210,150,0.4)",
              }}>
                <svg width="14" height="14" viewBox="0 0 14 14" fill="none" stroke="#fff" strokeWidth="2.4" strokeLinecap="round" strokeLinejoin="round">
                  <polyline points="2,7 5.5,10.5 12,3.5"/>
                </svg>
              </span>
            )}

            {/* clear button */}
            {hasValue && !isValid && (
              <button type="button" onClick={() => onChange("")} style={{
                width: 28, height: 28, borderRadius: "50%",
                background: "rgba(255,255,255,0.1)",
                border: "1px solid rgba(255,255,255,0.15)",
                cursor: "pointer",
                display: "flex", alignItems: "center", justifyContent: "center",
                flexShrink: 0, padding: 0,
                transition: "background 0.15s",
              }}
              onMouseEnter={e => e.currentTarget.style.background = "rgba(255,255,255,0.2)"}
              onMouseLeave={e => e.currentTarget.style.background = "rgba(255,255,255,0.1)"}
              >
                <svg width="10" height="10" viewBox="0 0 10 10" fill="none" stroke="rgba(255,255,255,0.7)" strokeWidth="2" strokeLinecap="round">
                  <line x1="1.5" y1="1.5" x2="8.5" y2="8.5"/>
                  <line x1="8.5" y1="1.5" x2="1.5" y2="8.5"/>
                </svg>
              </button>
            )}
          </div>
        </div>
      </div>

      {/* domain suggestion chips */}
      {focused && chips.length > 0 && (
        <div style={{
          display: "flex", gap: 8, marginTop: 10,
          flexWrap: "wrap", paddingLeft: 4,
        }}>
          {chips.map((d, i) => (
            <button
              key={d}
              type="button"
              onMouseDown={(e) => { e.preventDefault(); acceptDomain(d); }}
              style={{
                background: "rgba(255,255,255,0.08)",
                backdropFilter: "blur(20px)",
                border: "1px solid rgba(255,255,255,0.18)",
                borderRadius: 100,
                padding: "7px 18px",
                color: "rgba(255,255,255,0.85)",
                fontSize: 13,
                fontFamily: "'League Spartan',sans-serif",
                cursor: "pointer",
                animation: `chipIn 0.18s ease ${i * 0.04}s both`,
                transition: "background 0.15s, border-color 0.15s",
              }}
              onMouseEnter={e => {
                e.currentTarget.style.background = "rgba(168,85,247,0.22)";
                e.currentTarget.style.borderColor = "rgba(168,85,247,0.5)";
              }}
              onMouseLeave={e => {
                e.currentTarget.style.background = "rgba(255,255,255,0.08)";
                e.currentTarget.style.borderColor = "rgba(255,255,255,0.18)";
              }}
            >
              @{d}
            </button>
          ))}
        </div>
      )}

      {/* Tab hint */}
      {ghostTail && focused && (
        <p style={{
          marginTop: 6, marginLeft: 4,
          fontSize: 11.5, color: "rgba(255,255,255,0.38)",
          fontFamily: "'League Spartan',sans-serif",
          letterSpacing: 0.2,
        }}>
          Tab → to autocomplete
        </p>
      )}
    </div>
  );
}

