function StepStyle({ data, setData, onNext, onBack }) {
  const [ci, setCi] = useState(
    Math.max(0, PALETTE.findIndex((p) => p.name.toLowerCase() === (data.color || "").toLowerCase()))
  );
  const [fi, setFi] = useState(Math.max(0, FITS.indexOf(data.fit)));
  const [colorFamily, setColorFamily] = useState("All");

  useEffect(() => {
    setData((d) => ({ ...d, color: PALETTE[ci].name, fit: FITS[fi] }));
  }, [ci, fi]);

  const sel = PALETTE[ci];

  const COLOR_FAMILIES = {
    All:     PALETTE,
    Warm:    PALETTE.filter(p => ["Red","Orange","Yellow","Coral","Lime"].includes(p.name)),
    Cool:    PALETTE.filter(p => ["Green","Teal","Cyan","Blue","Navy","Indigo"].includes(p.name)),
    Purple:  PALETTE.filter(p => ["Purple","Indigo","Blush"].includes(p.name)),
    Pink:    PALETTE.filter(p => ["Pink","Rose","Blush","Coral"].includes(p.name)),
    Neutral: PALETTE.filter(p => ["Black","Grey","Brown","Mocha","Olive"].includes(p.name)),
  };
  const visibleColors = COLOR_FAMILIES[colorFamily] || PALETTE;

  const EXTRA_CSS = `
    @keyframes labelPop {
      from { opacity:0; transform:translateY(5px) scale(0.9); }
      to   { opacity:1; transform:translateY(0)   scale(1);   }
    }
    @keyframes orbPulse {
      0%,100% { transform:scale(1);    opacity:0.7; }
      50%      { transform:scale(1.06); opacity:1;   }
    }
    @keyframes fitRise {
      from { transform:translateY(8px) scale(0.96); opacity:0; }
      to   { transform:translateY(0)   scale(1);    opacity:1; }
    }
    .no-sb::-webkit-scrollbar { display:none; }
    .no-sb { -ms-overflow-style:none; scrollbar-width:none; }
  `;

  return (
    <Screen bg={BG2}>
      <style>{CSS + EXTRA_CSS}</style>
      <StepBar step={1} />
      <GlassCard style={{ padding:0, overflow:"hidden" }}>

        {/* ══════════════════════════════════════════
            COLOUR BANNER
        ══════════════════════════════════════════ */}
        <div style={{
          position:"relative", overflow:"hidden",
          background:`linear-gradient(148deg, ${sel.hex} 0%, ${sel.hex}99 40%, #13042a 100%)`,
          transition:"background 0.5s cubic-bezier(0.4,0,0.2,1)",
          padding:"26px 28px 28px",
          minHeight:260,
        }}>
          {/* ── Decorative orb fills dead top-right space ── */}
          <div style={{
            position:"absolute", right:-40, top:-40,
            width:300, height:300, borderRadius:"50%",
            background:`radial-gradient(circle at 40% 40%, ${sel.hex}90 0%, ${sel.hex}30 50%, transparent 75%)`,
            filter:"blur(18px)",
            transition:"background 0.5s",
            pointerEvents:"none",
            animation:"orbPulse 5s ease-in-out infinite",
          }}/>
          {/* outer ring */}
          <div style={{ position:"absolute", right:-20, top:-20, width:260, height:260, borderRadius:"50%", border:`1.5px solid rgba(255,255,255,0.13)`, pointerEvents:"none" }}/>
          <div style={{ position:"absolute", right:-55, top:-55, width:330, height:330, borderRadius:"50%", border:`1px solid rgba(255,255,255,0.07)`, pointerEvents:"none" }}/>
          {/* shimmer top-right */}
          <div style={{ position:"absolute", inset:0, background:"radial-gradient(ellipse at 85% 5%, rgba(255,255,255,0.18) 0%, transparent 45%)", pointerEvents:"none" }}/>
          {/* dark bottom-left */}
          <div style={{ position:"absolute", inset:0, background:"radial-gradient(ellipse at 0% 100%, rgba(0,0,0,0.5) 0%, transparent 50%)", pointerEvents:"none" }}/>

          {/* ── Title + SIZE ── */}
          <div style={{ display:"flex", justifyContent:"space-between", alignItems:"flex-start", marginBottom:18, position:"relative" }}>
            <div>
              <div style={{ fontFamily:"'League Spartan'", fontWeight:300, fontSize:11, color:"rgba(255,255,255,0.6)", letterSpacing:4, textTransform:"uppercase" }}>Your Style</div>
              <div style={{ fontFamily:"'League Spartan'", fontWeight:900, fontSize:"min(48px,5vw)", color:"#fff", letterSpacing:-2, lineHeight:0.9, textShadow:"0 3px 18px rgba(0,0,0,0.3)" }}>Preference</div>
            </div>
            <div style={{ display:"flex", flexDirection:"column", alignItems:"flex-end", gap:5, position:"relative" }}>
              <div style={{ fontSize:8, fontWeight:700, letterSpacing:3, color:"rgba(255,255,255,0.55)", fontFamily:"'League Spartan'" }}>SIZE</div>
              <div style={{ display:"flex", gap:5, flexWrap:"wrap", maxWidth:200, justifyContent:"flex-end" }}>
                {SIZES.map((s) => {
                  const active = data.size === s;
                  return (
                    <button key={s} onClick={() => setData((d) => ({ ...d, size: s }))} style={{
                      padding:"7px 15px", borderRadius:100, border:"none", cursor:"pointer",
                      fontFamily:"'League Spartan'", fontSize:13, fontWeight: active ? 700 : 400,
                      background: active ? "rgba(255,255,255,0.96)" : "rgba(0,0,0,0.3)",
                      color: active ? "#0d0018" : "rgba(255,255,255,0.85)",
                      backdropFilter:"blur(12px)",
                      boxShadow: active ? "0 3px 16px rgba(0,0,0,0.45), 0 0 0 2px rgba(255,255,255,0.35)" : "none",
                      transform: active ? "scale(1.07)" : "scale(1)",
                      transition:"all 0.22s cubic-bezier(0.34,1.56,0.64,1)",
                    }}>{s}</button>
                  );
                })}
              </div>
            </div>
          </div>

          {/* ── Colour name + hex ── */}
          <div style={{ position:"relative", marginBottom:24 }}>
            <div style={{
              fontFamily:"'League Spartan'", fontWeight:900,
              fontSize:"min(80px,8.5vw)", color:"#fff",
              letterSpacing:-3, lineHeight:0.8,
              textShadow:"0 6px 32px rgba(0,0,0,0.3)",
              transition:"all 0.4s cubic-bezier(0.4,0,0.2,1)",
            }}>{sel.name}</div>
            <div style={{ fontFamily:"monospace", fontSize:12, color:"rgba(255,255,255,0.45)", letterSpacing:3, marginTop:10 }}>{sel.hex.toUpperCase()}</div>
          </div>

          {/* ── Fabric swatches ── */}
          <div className="no-sb" style={{ display:"flex", gap:7, overflowX:"auto", alignItems:"flex-end" }}>
            {PALETTE.map((p, idx) => {
              const active = idx === ci;
              return (
                <button key={idx} onClick={() => setCi(idx)} title={p.name} style={{
                  border:"none", padding:0, background:"none", cursor:"pointer",
                  flexShrink:0, display:"flex", flexDirection:"column", alignItems:"center", gap:6,
                }}>
                  <div style={{
                    width: active ? 50 : 34, height: active ? 84 : 60,
                    borderRadius:12,
                    background:`linear-gradient(165deg, ${p.hex} 0%, ${p.hex}cc 100%)`,
                    border: active ? "2.5px solid rgba(255,255,255,0.95)" : "1.5px solid rgba(255,255,255,0.2)",
                    boxShadow: active
                      ? `0 14px 40px ${p.hex}cc, 0 0 0 4px rgba(255,255,255,0.18), inset 0 1px 0 rgba(255,255,255,0.35)`
                      : `0 4px 14px ${p.hex}50, inset 0 1px 0 rgba(255,255,255,0.18)`,
                    transition:"all 0.3s cubic-bezier(0.34,1.56,0.64,1)",
                    position:"relative", overflow:"hidden",
                  }}>
                    <div style={{ position:"absolute", inset:0, background:"linear-gradient(165deg,rgba(255,255,255,0.3) 0%,transparent 55%)" }}/>
                    {active && (
                      <div style={{ position:"absolute", inset:0, display:"flex", alignItems:"center", justifyContent:"center" }}>
                        <div style={{
                          width:24, height:24, borderRadius:"50%",
                          background:"rgba(255,255,255,0.32)", backdropFilter:"blur(6px)",
                          display:"flex", alignItems:"center", justifyContent:"center",
                          boxShadow:"0 2px 8px rgba(0,0,0,0.3)",
                        }}>
                          <svg width="11" height="11" viewBox="0 0 11 11" fill="none" stroke="#fff" strokeWidth="2.5" strokeLinecap="round" strokeLinejoin="round">
                            <polyline points="1.5,5.5 4,8.5 9.5,2.5"/>
                          </svg>
                        </div>
                      </div>
                    )}
                  </div>
                  {active && (
                    <div style={{
                      fontFamily:"'League Spartan'", fontSize:10, fontWeight:700,
                      color:"rgba(255,255,255,0.88)", whiteSpace:"nowrap", letterSpacing:0.5,
                      animation:"labelPop 0.25s cubic-bezier(0.34,1.56,0.64,1)",
                    }}>{p.name}</div>
                  )}
                </button>
              );
            })}
          </div>
        </div>

        {/* ══════════════════════════════════════════
            FIT SECTION
        ══════════════════════════════════════════ */}
        <div style={{ padding:"26px 28px 28px" }}>
          {/* FIT header with line */}
          <div style={{ display:"flex", alignItems:"center", gap:12, marginBottom:20 }}>
            <span style={{ fontSize:9, fontWeight:700, letterSpacing:3, color:"rgba(255,255,255,0.3)", fontFamily:"'League Spartan'", flexShrink:0 }}>FIT</span>
            <div style={{ flex:1, height:"1px", background:"linear-gradient(90deg, rgba(255,255,255,0.12) 0%, transparent 100%)" }}/>
          </div>

          <div className="fit-grid" style={{ display:"grid", gridTemplateColumns:"repeat(4,1fr)", gap:14 }}>
            {FIT_META.map((f, i) => {
              const active = i === fi;
              const dimBg   = f.glow.replace(/[\d.]+\)$/, "0.12)");
              const dimBrd  = f.glow.replace(/[\d.]+\)$/, "0.3)");
              const iconCol = f.glow.replace(/[\d.]+\)$/, "0.85)");
              return (
                <button key={i} onClick={() => setFi(i)} style={{ border:"none", padding:0, background:"none", cursor:"pointer" }}>
                  {/* outer: gradient border when active, coloured border when inactive */}
                  <div style={{
                    borderRadius:22, padding:"2px",
                    background: active ? f.gradient : "none",
                    border: active ? "none" : `1.5px solid ${dimBrd}`,
                    boxShadow: active
                      ? `0 18px 52px ${f.glow}, 0 4px 18px rgba(0,0,0,0.45)`
                      : `0 4px 20px rgba(0,0,0,0.25)`,
                    transform: active ? "translateY(-8px) scale(1.05)" : "translateY(0) scale(1)",
                    transition:"all 0.35s cubic-bezier(0.34,1.56,0.64,1)",
                    animation: active ? "fitRise 0.35s ease" : "none",
                  }}>
                    <div style={{
                      borderRadius:20, padding:"28px 10px 22px",
                      background: active
                        ? "linear-gradient(155deg,rgba(12,3,30,0.5),rgba(4,1,14,0.88))"
                        : `linear-gradient(160deg, ${dimBg} 0%, rgba(8,3,20,0.7) 100%)`,
                      backdropFilter:"blur(24px)",
                      display:"flex", flexDirection:"column", alignItems:"center", gap:10,
                      position:"relative", overflow:"hidden", minHeight:158,
                    }}>
                      {/* active shimmer */}
                      {active && <div style={{ position:"absolute", inset:0, background:"linear-gradient(148deg,rgba(255,255,255,0.14) 0%,transparent 48%)", pointerEvents:"none" }}/>}
                      {/* inactive top-colour fade */}
                      {!active && <div style={{ position:"absolute", top:0, left:0, right:0, height:"60%", background:`linear-gradient(180deg, ${dimBg} 0%, transparent 100%)`, pointerEvents:"none" }}/>}

                      {/* checkmark badge */}
                      {active && (
                        <div style={{
                          position:"absolute", top:12, right:12,
                          width:26, height:26, borderRadius:"50%",
                          background:"rgba(255,255,255,0.28)", backdropFilter:"blur(8px)",
                          display:"flex", alignItems:"center", justifyContent:"center",
                          boxShadow:"0 2px 8px rgba(0,0,0,0.3)",
                        }}>
                          <svg width="12" height="12" viewBox="0 0 12 12" fill="none" stroke="#fff" strokeWidth="2.4" strokeLinecap="round" strokeLinejoin="round">
                            <polyline points="2,6 5,9 10,3"/>
                          </svg>
                        </div>
                      )}

                      {/* t-shirt SVG */}
                      <div style={{
                        opacity: active ? 1 : 0.65,
                        transform: active ? "scale(1.14)" : "scale(1)",
                        filter: active ? "none" : "saturate(0.4) brightness(1.6)",
                        color: active ? "#fff" : iconCol,
                        transition:"all 0.35s",
                      }}>{f.svg}</div>

                      {/* label */}
                      <div style={{
                        fontFamily:"'League Spartan'", fontSize:15, fontWeight: active ? 800 : 600,
                        color: active ? "#fff" : "rgba(255,255,255,0.52)",
                        letterSpacing: active ? -0.3 : 0, transition:"all 0.25s",
                      }}>{f.label}</div>

                      {/* desc */}
                      <div style={{
                        fontFamily:"'League Spartan'", fontSize:9, fontWeight:300,
                        color: active ? "rgba(255,255,255,0.78)" : "rgba(255,255,255,0.3)",
                        textAlign:"center", lineHeight:1.5, transition:"all 0.25s",
                      }}>{f.desc}</div>
                    </div>
                  </div>
                </button>
              );
            })}
          </div>
        </div>

        {/* ══ WHAT ARE YOU LOOKING FOR? ══ */}
        {(() => {
          const g = (data.gender || "").toLowerCase();
          const isMen = g === "men" || g === "male" || g === "man";
          const CAT_OPTIONS = isMen
            ? [
                { label:"T-Shirts",  val:"t-shirt",  emoji:"👕" },
                { label:"Shirts",    val:"shirt",    emoji:"👔" },
                { label:"Jeans",     val:"pant",     emoji:"👖" },
                { label:"Trousers",  val:"trousers", emoji:"🩳" },
                { label:"Jackets",   val:"jacket",   emoji:"🧥" },
                { label:"Blazers",   val:"blazer",   emoji:"🤵" },
                { label:"Kurtas",    val:"kurta",    emoji:"🪭" },
                { label:"Activewear",val:"active",   emoji:"🏃" },
              ]
            : [
                { label:"Dresses",   val:"dress",    emoji:"👗" },
                { label:"Tops",      val:"top",      emoji:"👚" },
                { label:"Blouses",   val:"blouse",   emoji:"🌸" },
                { label:"Jeans",     val:"pant",     emoji:"👖" },
                { label:"Skirts",    val:"skirt",    emoji:"🩴" },
                { label:"Jumpsuits", val:"jumpsuit", emoji:"🧑‍🎤" },
                { label:"Kurtas",    val:"kurta",    emoji:"🪭" },
                { label:"Activewear",val:"active",   emoji:"🏃" },
              ];
          const sel = data.categories || [];
          const toggle = (val) => {
            const next = sel.includes(val) ? sel.filter(v => v !== val) : [...sel, val];
            setData(d => ({ ...d, categories: next }));
          };
          return (
            <div style={{ padding:"0 28px 24px" }}>
              <div style={{ fontFamily:"'League Spartan'", fontSize:13, fontWeight:600, color:"rgba(255,255,255,0.55)", letterSpacing:2, textTransform:"uppercase", marginBottom:12 }}>
                What are you looking for? <span style={{ color:"rgba(255,255,255,0.3)", fontWeight:300, letterSpacing:0 }}>(pick any)</span>
              </div>
              <div style={{ display:"flex", gap:8, flexWrap:"wrap" }}>
                {CAT_OPTIONS.map(({ label, val, emoji }) => {
                  const active = sel.includes(val);
                  return (
                    <button key={val} onClick={() => toggle(val)} style={{
                      display:"flex", alignItems:"center", gap:6,
                      padding:"8px 16px", borderRadius:50,
                      background: active ? "rgba(255,255,255,0.92)" : "rgba(255,255,255,0.08)",
                      border: active ? "none" : "1px solid rgba(255,255,255,0.18)",
                      color: active ? "#0d0018" : "rgba(255,255,255,0.75)",
                      fontFamily:"'League Spartan'", fontSize:13, fontWeight: active ? 700 : 400,
                      cursor:"pointer", transition:"all 0.18s",
                    }}>
                      <span style={{ fontSize:15 }}>{emoji}</span>
                      {label}
                      {active && <span style={{ fontSize:11, background:"#7c3aed", color:"#fff", borderRadius:"50%", width:16, height:16, display:"flex", alignItems:"center", justifyContent:"center" }}>✓</span>}
                    </button>
                  );
                })}
              </div>
              {sel.length > 0 && (
                <div style={{ marginTop:8, fontSize:12, color:"rgba(255,255,255,0.4)", fontFamily:"'League Spartan'" }}>
                  ✦ Recommending: <span style={{ color:"rgba(255,255,255,0.7)" }}>{sel.map(v => CAT_OPTIONS.find(c=>c.val===v)?.label || v).join(", ")}</span>
                </div>
              )}
            </div>
          );
        })()}

        {/* ══ FOOTER ══ */}
        <div style={{ display:"flex", gap:12, padding:"0 28px 28px" }}>
          <BackBtn onClick={onBack} />
          <ContinueBtn onClick={onNext} disabled={!(data.color && data.fit && data.size)}>Continue</ContinueBtn>
        </div>
      </GlassCard>
    </Screen>
  );
}

